      "keystrokes": "cat > /app/src/App.jsx <<'EOF'\nimport React, { useEffect, useMemo, useRef, useState } from 'react';\nimport { PUZZLES, PUZZLE_ORDER } from './data/puzzles.js';\nimport {\n  canonicalKey,\n  canAddBridge,\n  computeCurrentCounts,\n  isVictory,\n} from './utils/hashiLogic.js';\n\nconst GRID = 40;\nconst W = 800;\nconst H = 600;\n\nfunction islandAtPixel(island) {\n  return { px: island.x * GRID, py: island.y * GRID };\n}\n\nfunction getIslandById(islands, id) {\n  return islands.find((i) => i.id === id) || null;\n}\n\nfunction getNearestIslandInDirection(islands, fromIsland, dir) {\n  // Only move to visible islands in same row/col in that direction; nearest by distance.\n  if (!fromIsland) return null;\n  let best = null;\n  let bestDist = Infinity;\n  for (const isl of islands) {\n    if (isl.id === fromIsland.id) continue;\n    if (dir === 'left' && isl.y === fromIsland.y && isl.x < fromIsland.x) {\n      const d = fromIsland.x - isl.x;\n      if (d < bestDist) { bestDist = d; best = isl; }\n    }\n    if (dir === 'right' && isl.y === fromIsland.y && isl.x > fromIsland.x) {\n      const d = isl.x - fromIsland.x;\n      if (d < bestDist) { bestDist = d; best = isl; }\n    }\n    if (dir === 'up' && isl.x === fromIsland.x && isl.y < fromIsland.y) {\n      const d = fromIsland.y - isl.y;\n      if (d < bestDist) { bestDist = d; best = isl; }\n    }\n    if (dir === 'down' && isl.x === fromIsland.x && isl.y > fromIsland.y) {\n      const d = isl.y - fromIsland.y;\n      if (d < bestDist) { bestDist = d; best = isl; }\n    }\n  }\n  return best;\n}\n\nfunction bridgeLinesForPair(from, to, count) {\n  // returns array of line endpoints in pixel coords, with slight offset for double bridges\n  const { px: x1, py: y1 } = islandAtPixel(from);\n  const { px: x2, py: y2 } = islandAtPixel(to);\n\n  const isH = y1 === y2;\n  const isV = x1 === x2;\n  const offset = 6;\n\n  if (count === 1) {\n    return [{ x1, y1, x2, y2 }];\n  }\n  if (count === 2) {\n   